#include <bits/stdc++.h>
using namespace std;
#define dbg(x) cerr<<#x" = "<<(x)<<endl;
#define ll long long
const int N=205;
int n,m,x,y,k,ans,dp[2][N][N];
string ss[N];
deque<int> dq;
int main()
{
	ios::sync_with_stdio(0);
	cin.tie(0),cout.tie(0);
//	freopen(".in","r",stdin);
//	freopen(".out","w",stdout);
	cin>>n>>m>>x>>y>>k;
	for(int i=1;i<=n;i++)
	{
		cin>>ss[i];
		ss[i]=" "+ss[i];
	}
	memset(dp,128,sizeof(dp));
	dp[0][x][y]=0;
	for(int num=1;num<=k;num++)
	{
		int s,t,d;
		cin>>s>>t>>d;
		if(d==1)
		{
			for(int i=1;i<=m;i++)
			{
				dq.clear();
				for(int j=n;j>=1;j--)
				{
					if(ss[j][i]=='x')
					{
						dq.clear();
						continue;
					}
					while(!dq.empty()&&dp[(num-1)%2][dq.back()][i]+dq.back()<=j+dp[(num-1)%2][j][i]) dq.pop_back();
					while(!dq.empty()&&dq.front()>j+t-s+1) dq.pop_front();
					dq.push_back(j);
					dp[num%2][j][i]=dp[(num-1)%2][dq.front()][i]+dq.front()-j;
					ans=max(ans,dp[num%2][j][i]);
				}
			}
		}
		if(d==2)
		{
			for(int i=1;i<=m;i++)
			{
				dq.clear();
				for(int j=1;j<=n;j++)
				{
					if(ss[j][i]=='x')
					{
						dq.clear();
						continue;
					}
					while(!dq.empty()&&dp[(num-1)%2][dq.back()][i]-dq.back()<=dp[(num-1)%2][j][i]-j) dq.pop_back();
					while(!dq.empty()&&j>dq.front()+t-s+1) dq.pop_front();
					dq.push_back(j);
					dp[num%2][j][i]=dp[(num-1)%2][dq.front()][i]-dq.front()+j;
					ans=max(ans,dp[num%2][j][i]);
				}
			}
		}
		if(d==3)
		{
			for(int i=1;i<=n;i++)
			{
				dq.clear();
				for(int j=m;j>=1;j--)
				{
					if(ss[i][j]=='x')
					{
						dq.clear();
						continue;
					}
					while(!dq.empty()&&dp[(num-1)%2][i][dq.back()]+dq.back()<=dp[(num-1)%2][i][j]+j) dq.pop_back();
					while(!dq.empty()&&dq.front()>j+t-s+1) dq.pop_front();
					dq.push_back(j);
					dp[num%2][i][j]=dp[(num-1)%2][i][dq.front()]+dq.front()-j;
					ans=max(ans,dp[num%2][i][j]);
				}
			}
		}
		if(d==4)
		{
			for(int i=1;i<=n;i++)
			{
				dq.clear();
				for(int j=1;j<=m;j++)
				{
					if(ss[i][j]=='x')
					{
						dq.clear();
						continue;
					}
					while(!dq.empty()&&dp[(num-1)%2][i][dq.back()]-dq.back()<=dp[(num-1)%2][i][j]-j) dq.pop_back();
					while(!dq.empty()&&j>dq.front()+t-s+1) dq.pop_front();
					dq.push_back(j);
					dp[num%2][i][j]=dp[(num-1)%2][i][dq.front()]-dq.front()+j;
					ans=max(ans,dp[num%2][i][j]);
				}
			}
		}
	}
	cout<<ans;
	return 0;
}
